**Production change:**
```diff
diff --git a/src/tasks/task-flow-registry.maintenance.ts b/src/tasks/task-flow-registry.maintenance.ts
index 1234567..abcdefg 100644
--- a/src/tasks/task-flow-registry.maintenance.ts
+++ b/src/tasks/task-flow-registry.maintenance.ts
@@ -54,6 +54,49 @@ function shouldFinalizeCancelledFlow(flow: TaskFlowRecord): boolean {
   return !hasActiveLinkedTasks(flow.flowId);
 }

+function shouldReconcileOrphanedManagedFlow(flow: TaskFlowRecord): boolean {
+  if (flow.syncMode !== "managed") return false;
+  if (flow.status !== "running" && flow.status !== "queued") return false;
+  if (flow.cancelRequestedAt != null) return false;
+  const tasks = listTasksForFlowId(flow.flowId);
+  if (tasks.length === 0) return false;
+  return !hasActiveLinkedTasks(flow.flowId);
+}
+
+function reconcileOrphanedManagedFlow(flow: TaskFlowRecord, now: number): boolean {
+  let current = flow;
+  for (let attempt = 0; attempt < 2; attempt += 1) {
+    const endedAt = Math.max(now, current.updatedAt, current.createdAt);
+    const result = updateFlowRecordByIdExpectedRevision({
+      flowId: current.flowId,
+      expectedRevision: current.revision,
+      patch: {
+        status: "lost",
+        blockedTaskId: null,
+        blockedSummary: null,
+        waitJson: null,
+        endedAt,
+        updatedAt: endedAt,
+      },
+    });
+    if (result.applied) return true;
+    if (result.reason === "not_found" || !result.current) return false;
+    current = result.current;
+    if (!shouldReconcileOrphanedManagedFlow(current)) return false;
+  }
+  return false;
+}
+
 // Preview and apply paths updated to call shouldReconcileOrphanedManagedFlow / reconcileOrphanedManagedFlow
```

